import React from "react";
import MapView from "./components/MapView";
import StatusBar from "./components/StatusBar";
import { useIss } from "./common/hooks";
import AppWrapper, { IssProvider, ThemeProvider } from "./layouts/appWrapper";
import compose from "./layouts/compose";

function IssTracker() {
  const { position, loading, error, lastUpdated } = useIss();

  return (
    <>
      <h1 style={{ fontSize: "24px", margin: "8px 0 14px" }}>Live ISS Tracker</h1>
      <MapView position={position} />
      <StatusBar
        position={position}
        loading={loading}
        error={error}
        lastUpdated={lastUpdated}
      />
    </>
  );
}

const Providers = compose(ThemeProvider, IssProvider, AppWrapper);

export default function App() {
  return (
    <Providers>
      <IssTracker />
    </Providers>
  );
}
